import (
	context "context"
	fern "github.com/go-undiscriminated-union-wire-tests/fern"
	fernclient "github.com/go-undiscriminated-union-wire-tests/fern/client"
	option "github.com/go-undiscriminated-union-wire-tests/fern/option"
)

client := fernclient.NewClient(
	option.WithToken(
		"<YOUR_AUTH_TOKEN>",
	),
)
response, err := client.Service.Rerank(
	context.TODO(),
	&fern.RerankRequest{
		Documents: []*fern.DocumentItem{
			&fern.DocumentItem{
				String: "documents",
			},
		},
		Query: "query",
	},
)
